const _XLSX_TPL = {"docProps/app.xml":"PFByb3BlcnRpZXMgeG1sbnM9Imh0dHA6Ly9zY2hlbWFzLm9wZW54bWxmb3JtYXRzLm9yZy9vZmZpY2VEb2N1bWVudC8yMDA2L2V4dGVuZGVkLXByb3BlcnRpZXMiPjxBcHBsaWNhdGlvbj5NaWNyb3NvZnQgRXhjZWwgQ29tcGF0aWJsZSAvIE9wZW5weXhsIDMuMS41PC9BcHBsaWNhdGlvbj48QXBwVmVyc2lvbj4zLjE8L0FwcFZlcnNpb24+PC9Qcm9wZXJ0aWVzPg==", "docProps/core.xml":"", "xl/theme/theme1.xml":"", "xl/worksheets/sheet1.xml":"", "xl/worksheets/sheet2.xml":"", "xl/styles.xml":"", "_rels/.rels":"", "xl/workbook.xml":"", "xl/_rels/workbook.xml.rels":"", "[Content_Types].xml":""};

function downloadTemplateImportacao() {
  if (typeof readZipEntries !== 'function') { alert('App não carregado corretamente.'); return; }

  const cats  = (typeof loadCats       === 'function') ? loadCats()       : [];
  const pags  = (typeof loadPagamentos === 'function') ? loadPagamentos() : [];
  const tercs = (typeof loadTerceiros  === 'function') ? loadTerceiros()  : [];

  const categorias = [...new Set(cats.map(c=>c.nome).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'pt-BR'));
  const subcats    = [...new Set(cats.flatMap(c=>(c.subs||[]).map(s=>typeof s==='object'?s.nome:s)).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'pt-BR'));
  const catSubPairs=[];
  cats.forEach(c=>{(c.subs||[]).forEach(s=>{const sn=typeof s==='object'?s.nome:s;if(sn)catSubPairs.push({cat:c.nome,sub:sn});});});
  catSubPairs.sort((a,b)=>a.cat.localeCompare(b.cat,'pt-BR')||a.sub.localeCompare(b.sub,'pt-BR'));
  const pagamentos = pags.map(p=>p.nome||p).filter(Boolean).sort((a,b)=>a.localeCompare(b,'pt-BR'));
  const terceiros  = tercs.map(t=>t.nome||t).filter(Boolean).sort((a,b)=>a.localeCompare(b,'pt-BR'));
  const tiposLanc  = ['Variavel','Parcelado','Fixo'];
  const tiposMov   = ['Despesa','Receita'];
  const pago       = ['Sim','Não'];

  const hoje = new Date();
  const mm   = String(hoje.getMonth()+1).padStart(2,'0');

  // Escapa texto para XML
  function xe(s){ return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }

  // Constrói o novo sheet1.xml (aba Listas) com os dados reais do usuário
  // O template tem estilos s=1(header) s=2(linhaA) s=3(linhaB) já definidos
  const lCols = ['A','B','C','D','E','F','G','H'];
  const maxLen = Math.max(categorias.length, subcats.length, catSubPairs.length,
                          pagamentos.length, terceiros.length, tiposLanc.length, pago.length, tiposMov.length, 1);

  // Lê o sheet1.xml do template para preservar cabeçalho e estrutura
  const tplSheet1B64 = _XLSX_TPL['xl/worksheets/sheet1.xml'];
  const tplSheet1Bytes = Uint8Array.from(atob(tplSheet1B64), c=>c.charCodeAt(0));
  let sheet1Xml = new TextDecoder().decode(tplSheet1Bytes);

  // Substitui o <sheetData> inteiro com os dados reais
  const sd1s = sheet1Xml.indexOf('<sheetData>');
  const sd1e = sheet1Xml.indexOf('</sheetData>') + '</sheetData>'.length;

  // Linha de cabeçalho (row 1) — mantém do template
  const hdrRowMatch = sheet1Xml.match(/<row r="1"[^>]*>[\s\S]*?<\/row>/);
  const hdrRow = hdrRowMatch ? hdrRowMatch[0] : '';

  let newSD1 = '<sheetData>' + hdrRow;
  for (let i=0; i<maxLen; i++) {
    const r = i+2; // começa em linha 2
    const s = r%2===0 ? 2 : 3; // s=2 par, s=3 ímpar (mesmo do template)
    const vals = [
      xe(categorias[i]||''),
      xe(subcats[i]||''),
      xe(catSubPairs[i] ? catSubPairs[i].cat+' > '+catSubPairs[i].sub : ''),
      xe(pagamentos[i]||''),
      xe(terceiros[i]||''),
      xe(tiposLanc[i]||''),
      xe(pago[i]||''),
      xe(tiposMov[i]||''),
    ];
    newSD1 += `<row r="${r}" ht="18" customHeight="1">`;
    lCols.forEach((col,ci)=>{
      const v = vals[ci];
      newSD1 += v
        ? `<c r="${col}${r}" s="${s}" t="inlineStr"><is><t>${v}</t></is></c>`
        : `<c r="${col}${r}" s="${s}" t="inlineStr"></c>`;
    });
    newSD1 += '</row>';
  }
  newSD1 += '</sheetData>';

  // Atualiza a dimensão da sheet
  const newDim = `A1:H${maxLen+1}`;
  const newSheet1 = sheet1Xml
    .slice(0, sd1s) + newSD1 + sheet1Xml.slice(sd1e);
  const newSheet1Final = newSheet1.replace(/ref="A1:H\d+"/, `ref="${newDim}"`);

  // Reconstrói o ZIP com sheet1 substituído; tudo mais do template intacto
  const enc = new TextEncoder();
  const sheet1Encoded = enc.encode(newSheet1Final);

  // Reconstrói o ZIP a partir do template base64
  const tplBytes = Uint8Array.from(atob(
    // Concatena todos os arquivos do template em um ZIP válido
    // Usa _rebuildZipFromTemplate que monta o ZIP a partir do objeto _XLSX_TPL
    ''), c=>c.charCodeAt(0));

  const result = _buildXlsxFromTemplate(_XLSX_TPL, {
    'xl/worksheets/sheet1.xml': sheet1Encoded
  });

  const blob = new Blob([result], {type:'application/octet-stream'});
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement('a');
  a.href=url; a.download=`Importador_${mm}${hoje.getFullYear()}.xlsx`; a.click();
  URL.revokeObjectURL(url);
}

// Constrói um XLSX a partir do objeto de template (base64 por arquivo)
// substituindo os arquivos indicados em replacements {name: Uint8Array}
function _buildXlsxFromTemplate(tpl, replacements) {
  const enc = new TextEncoder();
  const parts = [], cdRecs = [];
  let wOff = 0;

  for (const [name, b64] of Object.entries(tpl)) {
    const nb = enc.encode(name);
    let fileBytes;
    if (name in replacements) {
      fileBytes = replacements[name];
    } else {
      fileBytes = Uint8Array.from(atob(b64), c=>c.charCodeAt(0));
    }
    const crc = _crc32(fileBytes);
    const lhB = new Uint8Array(30+nb.length);
    const lhD = new DataView(lhB.buffer);
    lhD.setUint32(0,0x04034b50,true); lhD.setUint16(4,20,true); lhD.setUint16(6,0,true);
    lhD.setUint16(8,0,true); // store, no compression
    lhD.setUint16(10,0,true); lhD.setUint16(12,0,true);
    lhD.setUint32(14,crc,true);
    lhD.setUint32(18,fileBytes.length,true); lhD.setUint32(22,fileBytes.length,true);
    lhD.setUint16(26,nb.length,true); lhD.setUint16(28,0,true);
    lhB.set(nb,30);
    cdRecs.push({nb, offset:wOff, crc, size:fileBytes.length});
    parts.push(lhB, fileBytes);
    wOff += lhB.length + fileBytes.length;
  }

  const cdStart = wOff;
  cdRecs.forEach(({nb,offset,crc,size})=>{
    const cd = new Uint8Array(46+nb.length);
    const dv = new DataView(cd.buffer);
    dv.setUint32(0,0x02014b50,true); dv.setUint16(4,20,true); dv.setUint16(6,20,true);
    dv.setUint16(8,0,true); dv.setUint16(10,0,true);
    dv.setUint16(12,0,true); dv.setUint16(14,0,true);
    dv.setUint32(16,crc,true); dv.setUint32(20,size,true); dv.setUint32(24,size,true);
    dv.setUint16(28,nb.length,true); dv.setUint16(30,0,true); dv.setUint16(32,0,true);
    dv.setUint16(34,0,true); dv.setUint16(36,0,true);
    dv.setUint32(38,0,true); dv.setUint32(42,offset,true);
    cd.set(nb,46);
    parts.push(cd); wOff += cd.length;
  });

  const cdSize = wOff - cdStart;
  const eocd = new Uint8Array(22);
  const ev = new DataView(eocd.buffer);
  ev.setUint32(0,0x06054b50,true); ev.setUint16(4,0,true); ev.setUint16(6,0,true);
  ev.setUint16(8,cdRecs.length,true); ev.setUint16(10,cdRecs.length,true);
  ev.setUint32(12,cdSize,true); ev.setUint32(16,cdStart,true); ev.setUint16(20,0,true);
  parts.push(eocd);

  const total = parts.reduce((s,b)=>s+b.length,0);
  const res   = new Uint8Array(total);
  let p=0; parts.forEach(b=>{res.set(b,p);p+=b.length;});
  return res;
}

function _crc32(buf){
  const t=new Uint32Array(256);
  for(let i=0;i<256;i++){let n=i;for(let j=0;j<8;j++)n=n&1?(0xEDB88320^(n>>>1)):(n>>>1);t[i]=n;}
  let c=0xFFFFFFFF;
  for(let i=0;i<buf.length;i++) c=t[(c^buf[i])&0xFF]^(c>>>8);
  return (c^0xFFFFFFFF)>>>0;
}



function exportarBackup() {
  // Exporta sempre no formato longo (chaves completas) para máxima compatibilidade
  const lncsRaw = (typeof loadData === 'function') ? loadData() : [];
  const lncs = lncsRaw.length && (lncsRaw[0].i !== undefined || lncsRaw[0].t !== undefined)
    ? lncsRaw.map(_unpack)
    : lncsRaw;

  const backup = {
    version: 2,
    exportedAt: new Date().toISOString(),
    lancamentos:  lncs,
    provisoes:    (typeof loadProvisoes === 'function') ? loadProvisoes() : [],
    categorias:   (typeof loadCats === 'function') ? loadCats() : [],
    pagamentos:   (typeof loadPagamentos === 'function') ? loadPagamentos() : [],
    terceiros:    (typeof loadTerceiros === 'function') ? loadTerceiros() : [],
    bancos:       (typeof loadBancos === 'function') ? loadBancos() : [],
    bancoModo:    (typeof loadBancoModo === 'function') ? loadBancoModo() : 'consolidado',
    saldoInicial: (typeof loadSaldoInicial === 'function') ? loadSaldoInicial() : null,
    catmap:       (typeof loadCatMap === 'function') ? loadCatMap() : {},
    submap:       (typeof loadSubMap === 'function') ? loadSubMap() : {},
  };
  const blob = new Blob([JSON.stringify(backup, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  const d = new Date();
  a.href = url;
  a.download = `financeos-backup-${d.getFullYear()}${String(d.getMonth()+1).padStart(2,'0')}${String(d.getDate()).padStart(2,'0')}.json`;
  a.click();
  URL.revokeObjectURL(url);
}

function importarBackup(event) {
  const file = event.target.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = function(e) {
    try {
      var parsed = JSON.parse(e.target.result);

      // ── Detecta o formato do JSON ──────────────────────────────────────
      // Formato 1: backup completo do FinanceOS { lancamentos: [...], ... }
      // Formato 2: array direto de lançamentos [{ ... }, ...]
      // Formato 3: objeto com outra chave raiz contendo array de lançamentos
      var backup = {};
      var lncsRaw = [];

      if (Array.isArray(parsed)) {
        // Formato 2: array direto
        lncsRaw = parsed;
        console.log('[FinanceOS] Formato detectado: array direto de lançamentos');
      } else if (parsed && typeof parsed === 'object') {
        if (Array.isArray(parsed.lancamentos)) {
          // Formato 1: backup padrão do FinanceOS
          backup = parsed;
          lncsRaw = parsed.lancamentos;
          console.log('[FinanceOS] Formato detectado: backup padrão FinanceOS');
        } else {
          // Formato 3: tenta encontrar alguma chave que seja array de objetos com campos financeiros
          var foundKey = null;
          Object.keys(parsed).forEach(function(k) {
            if (!foundKey && Array.isArray(parsed[k]) && parsed[k].length > 0) {
              var primeiro = parsed[k][0];
              // Verifica se parece um lançamento (chaves longas ou curtas)
              var temCampos = primeiro.valor !== undefined || primeiro.v !== undefined ||
                              primeiro.tipo !== undefined || primeiro.t !== undefined ||
                              primeiro.desc !== undefined || primeiro.de !== undefined;
              if (temCampos) foundKey = k;
            }
          });
          if (foundKey) {
            lncsRaw = parsed[foundKey];
            backup = parsed;
            console.log('[FinanceOS] Formato detectado: objeto com chave "' + foundKey + '"');
          } else {
            alert('Arquivo JSON inválido — nenhuma lista de lançamentos encontrada.\n\nEsperado: backup do FinanceOS (.json exportado pelo botão ⬇ Backup) ou array de lançamentos.');
            event.target.value = '';
            return;
          }
        }
      } else {
        alert('Arquivo JSON inválido ou vazio.');
        event.target.value = '';
        return;
      }

      if (!lncsRaw.length) {
        alert('O arquivo não contém lançamentos.');
        event.target.value = '';
        return;
      }

      // ── Normaliza para formato LONGO (chaves completas) ─────────────────
      var primeiro = lncsRaw[0];
      var isCompactado = primeiro.i !== undefined || primeiro.t !== undefined || primeiro.m !== undefined;
      console.log('[FinanceOS] Formato chaves:', isCompactado ? 'compactado (curtas)' : 'longo (completas)',
                  '| Total:', lncsRaw.length);

      var lncs = isCompactado ? lncsRaw.map(_unpack) : lncsRaw;

      // ── Garante campos obrigatórios (mes/ano) ───────────────────────────
      lncs = lncs.map(function(l, idx) {
        // Se mes/ano estiverem faltando, tenta derivar da data
        if (!l.mes || !l.ano) {
          var ds = l.data || l.d || '';
          var m, a;
          if (/^\d{2}\/\d{2}\/\d{4}$/.test(ds)) {
            var p = ds.split('/'); m = parseInt(p[1]); a = parseInt(p[2]);
          } else if (/^\d{4}-\d{2}-\d{2}$/.test(ds)) {
            var p = ds.split('-'); m = parseInt(p[1]); a = parseInt(p[0]);
          }
          if (m && a) { l.mes = m; l.ano = a; }
          else {
            var now = new Date();
            l.mes = l.mes || now.getMonth() + 1;
            l.ano = l.ano || now.getFullYear();
          }
        }
        // Garante ID único
        if (!l.id) l.id = 'imp_' + Date.now() + '_' + idx;
        // Garante tipo
        if (!l.tipo) l.tipo = 'despesa';
        // Garante valor numérico
        if (typeof l.valor === 'string') l.valor = parseFloat(l.valor.replace(',', '.')) || 0;
        return l;
      });

      console.log('[FinanceOS] Primeiro normalizado:', JSON.stringify(lncs[0]));

      // ── Pergunta se quer substituir ou mesclar ──────────────────────────
      var existentes = loadData();
      var acao = 'substituir';
      if (existentes.length > 0) {
        var resp = confirm(
          'Já existem ' + existentes.length + ' lançamentos salvos.\n\n' +
          'Clique OK para SUBSTITUIR tudo pelos dados do arquivo.\n' +
          'Clique Cancelar para MESCLAR (adicionar ao que já existe).'
        );
        acao = resp ? 'substituir' : 'mesclar';
      }

      var lncsFinal;
      if (acao === 'mesclar') {
        // Evita duplicatas por ID
        var idsExistentes = new Set(existentes.map(function(l){ return l.id; }));
        var novos = lncs.filter(function(l){ return !idsExistentes.has(l.id); });
        lncsFinal = existentes.concat(novos);
        console.log('[FinanceOS] Mesclado:', novos.length, 'novos adicionados,', (lncs.length - novos.length), 'duplicatas ignoradas');
      } else {
        lncsFinal = lncs;
      }

      // Atualiza memCache imediatamente para a UI responder
      _memCache.lancamentos = lncsFinal;
      renderAll();

      // ── Salva no Supabase aguardando conclusão ──────────────────────────
      (async function() {
        var erros = [];
        try {
          await dbSaveLancamentos(lncsFinal);
        } catch(e) {
          erros.push('Lançamentos: ' + e.message);
          console.error('[import] dbSaveLancamentos ERRO:', e);
        }

        // Restaura outros dados do backup
        var extras = [
          { cond: backup.provisoes,                          fn: saveProvisoes,   arg: backup.provisoes,   nome: 'Provisões' },
          { cond: backup.categorias && backup.categorias.length, fn: saveCats,   arg: backup.categorias,  nome: 'Categorias' },
          { cond: backup.pagamentos && backup.pagamentos.length, fn: savePagamentos, arg: backup.pagamentos, nome: 'Pagamentos' },
          { cond: backup.terceiros  && backup.terceiros.length,  fn: saveTerceiros,  arg: backup.terceiros,  nome: 'Terceiros' },
          { cond: backup.bancos     && backup.bancos.length,     fn: saveBancos,     arg: backup.bancos,     nome: 'Bancos' },
          { cond: backup.bancoModo,  fn: saveBancoModo,  arg: backup.bancoModo,  nome: 'BancoModo' },
          { cond: backup.saldoInicial, fn: saveSaldoInicial, arg: backup.saldoInicial, nome: 'SaldoInicial' },
          { cond: backup.catmap,     fn: saveCatMap,     arg: backup.catmap,     nome: 'CatMap' },
          { cond: backup.submap,     fn: saveSubMap,     arg: backup.submap,     nome: 'SubMap' },
        ];
        for (var x = 0; x < extras.length; x++) {
          var ex = extras[x];
          if (ex.cond && typeof ex.fn === 'function') {
            try { await Promise.resolve(ex.fn(ex.arg)); }
            catch(e) { erros.push(ex.nome + ': ' + e.message); }
          }
        }

        var verificado = loadData();
        if (erros.length > 0) {
          alert('⚠️ Importação parcial!\n' + verificado.length + ' lançamentos no cache.\n\nErros ao salvar no Supabase:\n' + erros.join('\n'));
        } else {
          alert('✅ Importação concluída!\n' + verificado.length + ' lançamentos salvos no Supabase.' +
                (acao === 'mesclar' ? '\n(Mesclado com dados existentes)' : ''));
        }
      })();

    } catch(err) {
      console.error('[FinanceOS] Erro no import:', err);
      alert('Erro ao ler o arquivo JSON: ' + err.message + '\n\nVerifique se o arquivo é um JSON válido.');
    }
    event.target.value = '';
  };
  reader.readAsText(file);
}

// ======== DIAGNÓSTICO ========
function diagnostico() {
  var raw = _lsGet('financeos_lancamentos');
  if (!raw) { alert('localStorage VAZIO — nenhum dado salvo.'); return; }

  var arr;
  try { arr = JSON.parse(raw); } catch(e) { alert('ERRO ao parsear localStorage: ' + e.message); return; }

  if (!arr.length) { alert('Array de lancamentos VAZIO no localStorage.'); return; }

  var primeiro = arr[0];
  var isCompact = primeiro.i !== undefined || primeiro.m !== undefined;
  var total = arr.length;

  // Descompacta para contar por mes
  var lncs = isCompact ? arr.map(_unpack) : arr;
  var contaMes = {};
  lncs.forEach(function(l) {
    var k = (l.ano||'?') + '-' + String(l.mes||'?').padStart(2,'0');
    contaMes[k] = (contaMes[k]||0) + 1;
  });
  var mesesStr = Object.keys(contaMes).sort().map(function(k){ return k + ': ' + contaMes[k]; }).join('\n');

  var msg = 'DIAGNOSTICO FINANCEOS\n'
    + '========================\n'
    + 'Total lancamentos: ' + total + '\n'
    + 'Formato: ' + (isCompact ? 'compactado (chaves curtas)' : 'longo') + '\n'
    + 'Primeiro registro:\n'
    + '  id: ' + (lncs[0].id||'?') + '\n'
    + '  tipo: ' + (lncs[0].tipo||'?') + '\n'
    + '  mes: ' + (lncs[0].mes||'?') + ' / ano: ' + (lncs[0].ano||'?') + '\n'
    + '\nFiltro atual: ' + currentMonth + '/' + currentYear + '\n'
    + '\nLancamentos por mes:\n' + mesesStr;

  alert(msg);
}

